import {
  forwardRef,
  useCallback,
  useReducer,
  type JSXElementConstructor,
  type ComponentProps,
  useMemo,
} from 'react';

import { useId } from '../../../../core/hooks/useId.js';
import { DOMProps } from '../../../../core/types/dom.js';
import type { FormControlBaseProps } from '../../../../core/types/form-control-props.js';
import { WithChildren } from '../../../../core/types/with-children.js';
import { FormFieldMessageContext } from '../../contexts/FormFieldMessageContext.js';
import { useFormFieldContext } from '../../hooks/useFormFieldContext.js';
import { useFormFieldMessagesContext } from '../../hooks/useFormFieldMessagesContext.js';
import {
  formFieldMessagesReducer,
  type FormFieldMessagesReducerAction,
} from '../../state/formfield-messages-state-reducer.js';
import type { FormFieldMessageContextState } from '../../types/formfield-messages.types.js';
import type { SharedFormFieldProps } from '../../types/formfield.types.js';

type FormFieldMessageContextProviderProps = WithChildren &
  DOMProps &
  Pick<SharedFormFieldProps, 'disabled'>;

/**
 * Provides the FormFieldMessages context and handles default values properly, to easily reuse it when needed.
 * @internal
 */
export const FormFieldMessageContextProvider = /* @__PURE__ */ (
  formFieldProps: FormFieldMessageContextProviderProps,
) => {
  const generatedId = useId();
  const {
    children,
    id: propId = generatedId,
    disabled: propDisabled,
  }: FormFieldMessageContextProviderProps = formFieldProps;

  const formFieldState = useFormFieldContext();

  const formFieldMessageReducerCB = useCallback(
    (
      state: FormFieldMessageContextState,
      action: FormFieldMessagesReducerAction,
    ) => formFieldMessagesReducer(state, action),
    [],
  );

  const [state, dispatch] = useReducer(formFieldMessageReducerCB, {
    customMessages: [],
    formControlMessages: [],
    showError: false,
    isTouched: false,
    isValid: undefined,
    controlIds: [formFieldState.controlId ?? propId],
  });

  const formFieldMessageContextValue = useMemo(
    () => ({
      disabled: formFieldState.disabled || propDisabled,
      controlId: formFieldState.controlId || propId,
      dispatch,
      state,
    }),
    [
      formFieldState.disabled,
      formFieldState.controlId,
      propDisabled,
      propId,
      dispatch,
      state,
    ],
  );

  return (
    <FormFieldMessageContext.Provider value={formFieldMessageContextValue}>
      {children}
    </FormFieldMessageContext.Provider>
  );
};

/**
 * Function to ensure that a component with props that have generics in their type is always wrapped within a `MessageContextProvider`
 * for form validation outside of a `FormField`.
 * @internal
 */
export function withFormFieldMessageContextProviderWithGenerics<
  ComponentType extends JSXElementConstructor<FormControlBaseProps>,
>(OriginalComponent: ComponentType) {
  type Props = ComponentProps<ComponentType>;
  type RefType = Props extends { ref?: infer R } ? R : never;

  const WrappedComponent = forwardRef<RefType, Props>((props, forwardedRef) => {
    const { dispatch } = useFormFieldMessagesContext();

    if (dispatch !== undefined) {
      // the cast to any was necessary because the RefType and Props type cannot be easily/correctly inferred when we have generics
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      return <OriginalComponent ref={forwardedRef} {...(props as any)} />;
    }

    const { disabled, id } = props;

    return (
      <FormFieldMessageContextProvider disabled={disabled} id={id}>
        {/* the cast to any was necessary because the RefType and Props type cannot be easily/correctly inferred when we have generics */}
        {/* eslint-disable-next-line @typescript-eslint/no-explicit-any */}
        <OriginalComponent ref={forwardedRef} {...(props as any)} />
      </FormFieldMessageContextProvider>
    );
  });

  // The cast ensures the returned component retains generics when used in JSX
  return WrappedComponent as ComponentType;
}

/**
 * Function to ensure that an element is always wrapped within a MessageContextProvider for form validation outside of a `FormField`.
 * @internal
 */
export function withFormFieldMessageContextProvider<
  PropType extends FormControlBaseProps,
  RefType,
>(OriginalComponent: JSXElementConstructor<PropType>) {
  const WithFormFieldMessageContextProvider = forwardRef<RefType, PropType>(
    (props, forwardedRef) => {
      const { dispatch } = useFormFieldMessagesContext();

      if (dispatch !== undefined) {
        return <OriginalComponent ref={forwardedRef} {...props} />;
      }

      const { disabled, id } = props;

      return (
        <FormFieldMessageContextProvider disabled={disabled} id={id}>
          <OriginalComponent ref={forwardedRef} {...props} />
        </FormFieldMessageContextProvider>
      );
    },
  );

  return WithFormFieldMessageContextProvider;
}

(
  FormFieldMessageContextProvider as typeof FormFieldMessageContextProvider & {
    displayName: string;
  }
).displayName = 'FormFieldMessageContextProvider';
